package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.Constructor;
import java.lang.reflect.InvocationTargetException;

public class CSVFormatTest {

    @Test
    public void testGetHeaderComments() throws NoSuchMethodException, IllegalAccessException, InvocationTargetException, InstantiationException {
        // Given
        Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(char.class, Character.class, QuoteMode.class,
                Character.class, Character.class, boolean.class, boolean.class, String.class, String.class, Object[].class, String[].class,
                boolean.class, boolean.class, boolean.class, boolean.class, boolean.class);
        constructor.setAccessible(true);
        CSVFormat csvFormat = constructor.newInstance(',', '\"', null, '#', '\\', true, false, "\r\n",
                "\\N", new Object[]{"Header comment 1", "Header comment 2"}, new String[]{"Header1", "Header2"},
                false, true, false, true, false);

        // When
        String[] headerComments = csvFormat.getHeaderComments();

        // Then
        assertNotNull(headerComments);
        assertArrayEquals(new String[]{"Header comment 1", "Header comment 2"}, headerComments);
    }
}
